     5→//! Gallops write operations
     6→//!
     7→//! All mutation operations on Gallops: nominate, slate, rail, tally, draft, retire, furlough.
     8→
     9→use std::collections::{BTreeMap, HashSet};
    10→use std::fs;
    11→use std::path::Path;
    12→use crate::jjrf_favor::{jjrf_Firemark as Firemark, jjrf_Coronet as Coronet, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX, JJRF_CORONET_PREFIX as CORONET_PREFIX};
    13→use crate::jjrs_steeplechase::jjrs_SteeplechaseEntry as SteeplechaseEntry;
    14→use crate::jjrt_types::*;
    15→use crate::jjru_util::{zjjrg_increment_seed, jjrg_make_tack};
    16→use crate::jjrv_validate::{zjjrg_is_kebab_case, zjjrg_is_yymmdd};
    17→
    18→/// Nominate a new Heat
    19→///
    20→/// Creates a new Heat with empty Pace structure and creates the paddock file.
    21→pub fn jjrg_nominate(gallops: &mut jjrg_Gallops, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
    22→    // Validate silks is kebab-case
    23→    if !zjjrg_is_kebab_case(&args.silks) {
    24→        return Err(format!("silks must be kebab-case, got '{}'", args.silks));
    25→    }
    26→
    27→    // Validate created is YYMMDD
    28→    if !zjjrg_is_yymmdd(&args.created) {
    29→        return Err(format!("created must be YYMMDD format, got '{}'", args.created));
    30→    }
    31→
    32→    // Allocate Firemark from next_heat_seed
    33→    let firemark_str = format!("{}{}", FIREMARK_PREFIX, gallops.next_heat_seed);
    34→    let heat_id = gallops.next_heat_seed.clone();
    35→
    36→    // Compute paddock path
    37→    let paddock_file = format!(".claude/jjm/jjp_{}.md", heat_id);
    38→
    39→    // Create paddock file with template
    40→    let paddock_path = base_path.join(&paddock_file);
    41→    if let Some(parent) = paddock_path.parent() {
    42→        fs::create_dir_all(parent)
    43→            .map_err(|e| format!("Failed to create paddock directory: {}", e))?;
    44→    }
    45→
    46→    let paddock_content = format!(
    47→        "# Paddock: {}\n\n## Context\n\n(Describe the initiative's background and goals)\n\n## References\n\n(List relevant files, docs, or prior work)\n",
    48→        args.silks
    49→    );
    50→
    51→    fs::write(&paddock_path, paddock_content)
    52→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
    53→
    54→    // Create new Heat
    55→    let heat = jjrg_Heat {
    56→        silks: args.silks,
    57→        creation_time: args.created,
    58→        status: jjrg_HeatStatus::Racing,
    59→        order: Vec::new(),
    60→        next_pace_seed: "AAA".to_string(),
    61→        paddock_file,
    62→        paces: BTreeMap::new(),
    63→    };
    64→
    65→    // Insert Heat
    66→    gallops.heats.insert(firemark_str.clone(), heat);
    67→
    68→    // Increment next_heat_seed
    69→    gallops.next_heat_seed = zjjrg_increment_seed(&gallops.next_heat_seed);
    70→
    71→    Ok(jjrg_NominateResult { firemark: firemark_str })
    72→}
