   333→/// Tally - add a new Tack to a Pace
   334→///
   335→/// Prepends a new Tack with state transition and/or plan refinement.
   336→pub fn jjrg_tally(gallops: &mut jjrg_Gallops, args: jjrg_TallyArgs) -> Result<(), String> {
   337→    // Parse and normalize coronet
   338→    let coronet = Coronet::jjrf_parse(&args.coronet)
   339→        .map_err(|e| format!("Invalid coronet: {}", e))?;
   340→    let coronet_key = coronet.jjrf_display();
   341→
   342→    // Extract parent Firemark
   343→    let firemark = coronet.jjrf_parent_firemark();
   344→    let firemark_key = firemark.jjrf_display();
   345→
   346→    // Verify Heat exists
   347→    let heat = gallops.heats.get_mut(&firemark_key)
   348→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   349→
   350→    // Verify Pace exists
   351→    let pace = heat.paces.get_mut(&coronet_key)
   352→        .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
   353→
   354→    // Read current Tack
   355→    let current_tack = pace.tacks.first()
   356→        .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
   357→
   358→    // Determine new state
   359→    let new_state = args.state.clone().unwrap_or_else(|| current_tack.state.clone());
   360→
   361→    // Determine new direction
   362→    let new_direction = match (&args.state, &new_state) {
   363→        // State explicitly set to bridled: direction required
   364→        (Some(jjrg_PaceState::Bridled), _) => {
   365→            match &args.direction {
   366→                Some(d) if !d.is_empty() => Some(d.clone()),
   367→                Some(_) => return Err("direction must not be empty when state is bridled".to_string()),
   368→                None => return Err("direction is required when state is bridled".to_string()),
   369→            }
   370→        }
   371→        // State explicitly set to something other than bridled: direction forbidden
   372→        (Some(_), _) => {
   373→            if args.direction.is_some() {
   374→                return Err("direction must be absent when state is not bridled".to_string());
   375→            }
   376→            None
   377→        }
   378→        // State inherited and was bridled: inherit direction
   379→        (None, jjrg_PaceState::Bridled) => {
   380→            args.direction.or_else(|| current_tack.direction.clone())
   381→        }
   382→        // State inherited and was not bridled: no direction
   383→        (None, _) => None,
   384→    };
   385→
   386→    // Determine new text
   387→    let new_text = args.text.unwrap_or_else(|| current_tack.text.clone());
   388→    if new_text.is_empty() {
   389→        return Err("text must not be empty".to_string());
   390→    }
   391→
   392→    // Determine new silks
   393→    let new_silks = args.silks.unwrap_or_else(|| current_tack.silks.clone());
   394→
   395→    // Create new Tack
   396→    let new_tack = jjrg_make_tack(
   397→        new_state,
   398→        new_text,
   399→        new_silks,
   400→        new_direction,
   401→    );
   402→
   403→    // Prepend to tacks array
   404→    pace.tacks.insert(0, new_tack);
   405→
   406→    Ok(())
   407→}
