   409→/// Draft - move a Pace from one Heat to another
   410→///
   411→/// Moves the pace to the destination heat with a new Coronet.
   412→/// All Tack history is preserved, with a new Tack recording the draft.
   413→/// State is NOT changed - draft is a move operation, not a state transition.
   414→pub fn jjrg_draft(gallops: &mut jjrg_Gallops, args: jjrg_DraftArgs) -> Result<jjrg_DraftResult, String> {
   415→    // Validate positioning mutual exclusivity
   416→    let position_count = [args.before.is_some(), args.after.is_some(), args.first]
   417→        .iter()
   418→        .filter(|&&x| x)
   419→        .count();
   420→    if position_count > 1 {
   421→        return Err("Only one of --before, --after, or --first may be specified".to_string());
   422→    }
   423→
   424→    // Parse and normalize source coronet
   425→    let source_coronet = Coronet::jjrf_parse(&args.coronet)
   426→        .map_err(|e| format!("Invalid coronet: {}", e))?;
   427→    let source_coronet_key = source_coronet.jjrf_display();
   428→
   429→    // Extract source Firemark from coronet
   430→    let source_firemark = source_coronet.jjrf_parent_firemark();
   431→    let source_firemark_key = source_firemark.jjrf_display();
   432→
   433→    // Parse and normalize destination firemark
   434→    let dest_firemark = Firemark::jjrf_parse(&args.to)
   435→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
   436→    let dest_firemark_key = dest_firemark.jjrf_display();
   437→
   438→    // Validate source and destination are different
   439→    if source_firemark_key == dest_firemark_key {
   440→        return Err("Cannot draft pace to same heat".to_string());
   441→    }
   442→
   443→    // Verify source heat exists
   444→    if !gallops.heats.contains_key(&source_firemark_key) {
   445→        return Err(format!("Source heat '{}' not found", source_firemark_key));
   446→    }
   447→
   448→    // Verify destination heat exists
   449→    if !gallops.heats.contains_key(&dest_firemark_key) {
   450→        return Err(format!("Heat '{}' not found", dest_firemark_key));
   451→    }
   452→
   453→    // Verify pace exists in source heat
   454→    {
   455→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
   456→        if !source_heat.paces.contains_key(&source_coronet_key) {
   457→            return Err(format!("Pace {} not found in heat {}", source_coronet_key, source_firemark_key));
   458→        }
   459→    }
   460→
   461→    // Validate positioning target if specified
   462→    let insert_position = if let Some(ref before_str) = args.before {
   463→        let target = Coronet::jjrf_parse(before_str)
   464→            .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   465→        let target_key = target.jjrf_display();
   466→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
   467→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
   468→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   469→        Some(pos)
   470→    } else if let Some(ref after_str) = args.after {
   471→        let target = Coronet::jjrf_parse(after_str)
   472→            .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   473→        let target_key = target.jjrf_display();
   474→        let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
   475→        let pos = dest_heat.order.iter().position(|c| c == &target_key)
   476→            .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
   477→        Some(pos + 1)
   478→    } else if args.first {
   479→        Some(0)
   480→    } else {
   481→        None // Append to end
   482→    };
   483→
   484→    // Remove pace from source heat
   485→    let source_heat = gallops.heats.get_mut(&source_firemark_key).unwrap();
   486→    let pace_data = source_heat.paces.remove(&source_coronet_key)
   487→        .ok_or_else(|| format!("Pace {} not found", source_coronet_key))?;
   488→    source_heat.order.retain(|c| c != &source_coronet_key);
   489→
   490→    // Get destination heat and allocate new coronet
   491→    let dest_heat = gallops.heats.get_mut(&dest_firemark_key).unwrap();
   492→    let new_coronet_str = format!("{}{}{}", CORONET_PREFIX, dest_firemark.jjrf_as_str(), dest_heat.next_pace_seed);
   493→
   494→    // Create new tack recording the draft
   495→    let first_tack = pace_data.tacks.first();
   496→    let draft_note = format!("Drafted from {} in {}.\n\n{}",
   497→        source_coronet_key, source_firemark_key,
   498→        first_tack.map(|t| t.text.as_str()).unwrap_or(""));
   499→
   500→    let draft_tack = jjrg_make_tack(
   501→        first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough),
   502→        draft_note,
   503→        first_tack.map(|t| t.silks.clone()).unwrap_or_default(),
   504→        first_tack.and_then(|t| t.direction.clone()),
   505→    );
   506→
   507→    // Build new pace with draft tack prepended
