   528→/// Retire a Heat
   529→///
   530→/// Creates trophy file, removes heat from gallops, deletes paddock file.
   531→/// Does NOT save gallops or commit - caller is responsible for that.
   532→pub fn jjrg_retire(
   533→    gallops: &mut jjrg_Gallops,
   534→    args: jjrg_RetireArgs,
   535→    base_path: &Path,
   536→    steeplechase: &[SteeplechaseEntry],
   537→) -> Result<jjrg_RetireResult, String> {
   538→    // Parse and normalize firemark
   539→    let firemark = Firemark::jjrf_parse(&args.firemark)
   540→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   541→    let firemark_key = firemark.jjrf_display();
   542→
   543→    // Validate today is YYMMDD
   544→    if !zjjrg_is_yymmdd(&args.today) {
   545→        return Err(format!("today must be YYMMDD format, got '{}'", args.today));
   546→    }
   547→
   548→    // Verify heat exists
   549→    let heat = gallops.heats.get(&firemark_key)
   550→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   551→
   552→    // Read paddock content before we remove anything
   553→    let paddock_path = base_path.join(&heat.paddock_file);
   554→    let paddock_content = fs::read_to_string(&paddock_path)
   555→        .map_err(|e| format!("Failed to read paddock file '{}': {}", heat.paddock_file, e))?;
   556→
   557→    // Build trophy content
   558→    let trophy_content = zjjrg_build_trophy_content(&firemark_key, heat, &paddock_content, &args.today, steeplechase)?;
   559→
   560→    // Compute trophy path: .claude/jjm/retired/jjh_<created>-r<today>-<silks>.md
   561→    let trophy_filename = format!(
   562→        "jjh_{}-r{}-{}.md",
   563→        heat.creation_time,
   564→        args.today,
   565→        heat.silks
   566→    );
   567→    let trophy_rel_path = format!(".claude/jjm/retired/{}", trophy_filename);
   568→    let trophy_full_path = base_path.join(&trophy_rel_path);
   569→
   570→    // Create retired directory if needed
   571→    if let Some(parent) = trophy_full_path.parent() {
   572→        fs::create_dir_all(parent)
   573→            .map_err(|e| format!("Failed to create retired directory: {}", e))?;
   574→    }
   575→
   576→    // Write trophy file
   577→    fs::write(&trophy_full_path, trophy_content)
   578→        .map_err(|e| format!("Failed to write trophy file: {}", e))?;
   579→
   580→    // Capture info for result before removing heat
   581→    let silks = heat.silks.clone();
   582→    let paddock_file = heat.paddock_file.clone();
   583→
   584→    // Remove heat from gallops (do NOT change next_heat_seed)
   585→    gallops.heats.remove(&firemark_key);
   586→
   587→    // Delete paddock file
   588→    if paddock_path.exists() {
   589→        fs::remove_file(&paddock_path)
   590→            .map_err(|e| format!("Failed to delete paddock file: {}", e))?;
   591→    }
   592→
   593→    Ok(jjrg_RetireResult {
   594→        trophy_path: trophy_rel_path,
   595→        paddock_path: paddock_file,
   596→        silks,
   597→        firemark: firemark_key,
   598→    })
   599→}
