   623→/// Build trophy markdown content
   624→fn zjjrg_build_trophy_content(
   625→    firemark_key: &str,
   626→    heat: &jjrg_Heat,
   627→    paddock_content: &str,
   628→    today: &str,
   629→    steeplechase: &[SteeplechaseEntry],
   630→) -> Result<String, String> {
   631→    let mut content = String::new();
   632→
   633→    // Header
   634→    content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
   635→    content.push_str(&format!("**Firemark:** {}\n", firemark_key));
   636→    content.push_str(&format!("**Created:** {}\n", heat.creation_time));
   637→    content.push_str(&format!("**Retired:** {}\n", today));
   638→    content.push_str("**Status:** retired\n\n");
   639→
   640→    // Paddock
   641→    content.push_str("## Paddock\n\n");
   642→    content.push_str(paddock_content);
   643→    if !paddock_content.ends_with('\n') {
   644→        content.push('\n');
   645→    }
   646→    content.push('\n');
   647→
   648→    // Paces (in order)
   649→    content.push_str("## Paces\n\n");
   650→    for coronet_key in &heat.order {
   651→        if let Some(pace) = heat.paces.get(coronet_key) {
   652→            // Get final state from most recent tack
   653→            let final_state = pace.tacks.first()
   654→                .map(|t| match t.state {
   655→                    jjrg_PaceState::Rough => "rough",
   656→                    jjrg_PaceState::Bridled => "bridled",
   657→                    jjrg_PaceState::Complete => "complete",
   658→                    jjrg_PaceState::Abandoned => "abandoned",
   659→                })
   660→                .unwrap_or("unknown");
   661→
   662→            let pace_silks = pace.tacks.first()
   663→                .map(|t| t.silks.as_str())
   664→                .unwrap_or("unknown");
   665→
   666→            content.push_str(&format!(
   667→                "### {} ({}) [{}]\n\n",
   668→                pace_silks, coronet_key, final_state
   669→            ));
   670→
   671→            // Tack history (newest first, as stored)
   672→            for tack in &pace.tacks {
   673→                let state_str = match tack.state {
   674→                    jjrg_PaceState::Rough => "rough",
   675→                    jjrg_PaceState::Bridled => "bridled",
   676→                    jjrg_PaceState::Complete => "complete",
   677→                    jjrg_PaceState::Abandoned => "abandoned",
   678→                };
   679→                content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
   680→                content.push_str(&tack.text);
   681→                if !tack.text.ends_with('\n') {
   682→                    content.push('\n');
   683→                }
   684→                if let Some(ref direction) = tack.direction {
   685→                    content.push_str(&format!("\n*Direction:* {}\n", direction));
   686→                }
   687→                content.push('\n');
   688→            }
   689→        }
   690→    }
   691→
   692→    // Steeplechase (newest first, as provided)
   693→    content.push_str("## Steeplechase\n\n");
   694→    if steeplechase.is_empty() {
   695→        content.push_str("(no entries)\n\n");
   696→    } else {
   697→        for entry in steeplechase {
   698→            // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
   699→            let identity = entry.coronet.as_deref().unwrap_or("Heat");
   700→            let action = entry.action.as_deref().unwrap_or("notch");
   701→            content.push_str(&format!(
   702→                "### {} - {} - {}\n\n",
   703→                entry.timestamp, identity, action
   704→            ));
   705→            content.push_str(&entry.subject);
   706→            if !entry.subject.ends_with('\n') {
   707→                content.push('\n');
   708→            }
   709→            content.push('\n');
   710→        }
   711→    }
   712→
   713→    Ok(content)
   714→}
