   716→/// Furlough a Heat - change status or rename
   717→///
   718→/// Updates heat status (racing/stabled) and/or silks.
   719→/// At least one change must be requested.
   720→pub fn jjrg_furlough(gallops: &mut jjrg_Gallops, args: jjrg_FurloughArgs) -> Result<(), String> {
   721→    // Validate at least one option provided
   722→    if !args.racing && !args.stabled && args.silks.is_none() {
   723→        return Err("At least one option required: --racing, --stabled, or --silks".to_string());
   724→    }
   725→
   726→    // Validate racing/stabled mutual exclusivity
   727→    if args.racing && args.stabled {
   728→        return Err("Cannot specify both --racing and --stabled".to_string());
   729→    }
   730→
   731→    // Validate silks if provided
   732→    if let Some(ref silks) = args.silks {
   733→        if !zjjrg_is_kebab_case(silks) {
   734→            return Err(format!("silks must be kebab-case, got '{}'", silks));
   735→        }
   736→    }
   737→
   738→    // Parse and normalize firemark
   739→    let firemark = Firemark::jjrf_parse(&args.firemark)
   740→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   741→    let firemark_key = firemark.jjrf_display();
   742→
   743→    // Verify Heat exists
   744→    let heat = gallops.heats.get_mut(&firemark_key)
   745→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   746→
   747→    // Check not retired (terminal state)
   748→    if heat.status == jjrg_HeatStatus::Retired {
   749→        return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
   750→    }
   751→
   752→    // Apply status change if requested
   753→    if args.racing {
   754→        if heat.status == jjrg_HeatStatus::Racing {
   755→            return Err(format!("Heat '{}' is already racing", firemark_key));
   756→        }
   757→        heat.status = jjrg_HeatStatus::Racing;
   758→    } else if args.stabled {
   759→        if heat.status == jjrg_HeatStatus::Stabled {
   760→            return Err(format!("Heat '{}' is already stabled", firemark_key));
   761→        }
   762→        heat.status = jjrg_HeatStatus::Stabled;
   763→    }
   764→
   765→    // Apply silks change if requested
   766→    if let Some(silks) = args.silks {
   767→        heat.silks = silks;
   768→    }
   769→
   770→    Ok(())
   771→}
